// ===================== ECO INDEXEDDB CACHE =====================
let _ecoDb = null;
const _ECO_DB_NAME = 'RegaliaECO';
const _ECO_STORE_NAME = 'openings';
const _ECO_DB_VERSION = 1;

function _openEcoDB() {
  return new Promise(function(resolve, reject) {
    if (_ecoDb) { resolve(_ecoDb); return; }
    try {
      const req = indexedDB.open(_ECO_DB_NAME, _ECO_DB_VERSION);
      req.onupgradeneeded = function(e) {
        const db = e.target.result;
        if (!db.objectStoreNames.contains(_ECO_STORE_NAME)) {
          db.createObjectStore(_ECO_STORE_NAME);
        }
      };
      req.onsuccess = function(e) {
        _ecoDb = e.target.result;
        // FIX: Handle versionchange event to prevent DB upgrade blocking
        _ecoDb.onversionchange = function() { _ecoDb.close(); _ecoDb = null; };
        resolve(_ecoDb);
      };
      req.onerror = function(e) {
        console.warn('IndexedDB not available for ECO cache');
        resolve(null);
      };
    } catch(e) {
      resolve(null);
    }
  });
}

function _saveEcoToCache(parsedData) {
  _openEcoDB().then(function(db) {
    if (!db) return;
    try {
      const tx = db.transaction(_ECO_STORE_NAME, 'readwrite');
      tx.objectStore(_ECO_STORE_NAME).put(parsedData, 'eco_openings');
    } catch(e) {}
  });
}

function _loadEcoFromCache() {
  return _openEcoDB().then(function(db) {
    if (!db) return null;
    return new Promise(function(resolve) {
      try {
        const tx = db.transaction(_ECO_STORE_NAME, 'readonly');
        const req = tx.objectStore(_ECO_STORE_NAME).get('eco_openings');
        req.onsuccess = function() { resolve(req.result || null); };
        req.onerror = function() { resolve(null); };
      } catch(e) { resolve(null); }
    });
  });
}

// Preload ECO data from IndexedDB cache (async, runs on startup)
let _ecoCachedData = null;
(function _preloadEcoCache() {
  _loadEcoFromCache().then(function(cached) {
    if (cached && Array.isArray(cached) && cached.length > 0) {
      _ecoCachedData = cached;
      console.log('ECO data loaded from IndexedDB cache (' + cached.length + ' openings)');
    }
  }).catch(function() {});
})();

